#include<bits/stdc++.h>
using namespace std;
unordered_map<string,int> f;
string s[100010];
bool cmp(string a,string b)
{
    return a.size()<b.size();
}
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        cin>>s[i];
    }
    sort(s+1,s+1+n,cmp);
    int ans=0;
    for(int i=1;i<=n;i++)
    {
        if(s[i].size()==1)
        {
            f[s[i]]=1;
            ans=max(ans,f[s[i]]);
            continue;
        }
        f[s[i]]=(f[s[i].substr(0,s[i].size()-1)]&f[s[i].substr(1,s[i].size()-1)]);
        if(f[s[i]])
        {
            ans=max(ans,(int)(s[i].size()));
        }
    }
    printf("%d",ans);
    return 0;
}
